import {
  circle, ellipse, rectangle, rounded_rectangle, segment, arc, ring,
  polygon, triangle,
  union, intersection, difference, dilate, erode, shell,
  render,
} from '../../src/index.js';

// --- Palette ---
const CREAM       = [245, 238, 220];
const TAN         = [210, 185, 145];
const RUST        = [180, 95,  45];
const DARK_BROWN  = [72,  42,  18];
const BRASS       = [195, 160, 80];
const LEATHER     = [140, 85,  40];
const SHADOW      = [38,  28,  16];

// ─────────────────────────────────────────────────────────────
// WHEELS (two large rings + hub + spokes)
// ─────────────────────────────────────────────────────────────
const WHEEL_R   = 0.42;
const LEFT_CX   = -0.42;
const RIGHT_CX  =  0.42;
const WHEEL_Y   = -0.28;

function wheel(cx) {
  const tire    = ring(WHEEL_R, 0.045, [cx, WHEEL_Y]);
  const hub     = circle(0.045, [cx, WHEEL_Y]);
  const hubRing = ring(0.045, 0.016, [cx, WHEEL_Y]);

  // 12 spokes — thin segments
  const NSPOKES = 12;
  const spokeList = [];
  for (let i = 0; i < NSPOKES; i++) {
    const a = (i / NSPOKES) * Math.PI * 2;
    const ix = cx + Math.cos(a) * 0.048;
    const iy = WHEEL_Y + Math.sin(a) * 0.048;
    const ox = cx + Math.cos(a) * (WHEEL_R - 0.025);
    const oy = WHEEL_Y + Math.sin(a) * (WHEEL_R - 0.025);
    spokeList.push(segment([ix, iy], [ox, oy], 0.007));
  }
  return union(tire, hub, hubRing, ...spokeList);
}

const wheelLeft  = wheel(LEFT_CX);
const wheelRight = wheel(RIGHT_CX);
const wheels     = union(wheelLeft, wheelRight);

// ─────────────────────────────────────────────────────────────
// FRAME (diamond frame: top-tube, down-tube, seat-tube, chain-stay, seat-stay)
// ─────────────────────────────────────────────────────────────
const BB_X = 0.0,   BB_Y = WHEEL_Y;          // bottom bracket (centre)
const HEAD_X = RIGHT_CX - 0.05, HEAD_Y = 0.20;  // head tube top
const SEAT_X = LEFT_CX + 0.18, SEAT_Y = 0.26;   // seat tube top

// top tube: seat top → head top
const topTube       = segment([SEAT_X, SEAT_Y],       [HEAD_X, HEAD_Y],      0.018);
// down tube: head top → BB
const downTube      = segment([HEAD_X, HEAD_Y - 0.04],[BB_X,   BB_Y],        0.018);
// seat tube: BB → seat top
const seatTube      = segment([BB_X,   BB_Y],          [SEAT_X, SEAT_Y],     0.018);
// chain stay: BB → left axle
const chainStay     = segment([BB_X,   BB_Y],          [LEFT_CX, WHEEL_Y],   0.016);
// seat stay: seat top → left axle
const seatStay      = segment([SEAT_X, SEAT_Y - 0.04],[LEFT_CX, WHEEL_Y],   0.013);
// fork: head top → right axle (two legs)
const forkR         = segment([HEAD_X, HEAD_Y - 0.04],[RIGHT_CX + 0.03, WHEEL_Y], 0.014);
const forkL         = segment([HEAD_X, HEAD_Y - 0.04],[RIGHT_CX - 0.03, WHEEL_Y], 0.014);

const frame = union(topTube, downTube, seatTube, chainStay, seatStay, forkR, forkL);

// ─────────────────────────────────────────────────────────────
// HEAD TUBE (short vertical cylinder)
// ─────────────────────────────────────────────────────────────
const headTube = rounded_rectangle([0.036, 0.10], 0.018, [HEAD_X, HEAD_Y - 0.05]);

// ─────────────────────────────────────────────────────────────
// HANDLEBAR STEM + BARS
// ─────────────────────────────────────────────────────────────
const stem       = segment([HEAD_X, HEAD_Y + 0.04], [HEAD_X - 0.02, HEAD_Y + 0.22], 0.016);
const handleBar  = segment([HEAD_X - 0.10, HEAD_Y + 0.26],[HEAD_X + 0.08, HEAD_Y + 0.18], 0.014);
const barGripL   = rounded_rectangle([0.024, 0.055], 0.012, [HEAD_X - 0.105, HEAD_Y + 0.245]);
const barGripR   = rounded_rectangle([0.024, 0.055], 0.012, [HEAD_X + 0.083, HEAD_Y + 0.165]);
const handlebar  = union(stem, handleBar, barGripL, barGripR);

// ─────────────────────────────────────────────────────────────
// SEAT POST + SADDLE (classic leather saddle)
// ─────────────────────────────────────────────────────────────
const seatPost   = segment([SEAT_X, SEAT_Y], [SEAT_X, SEAT_Y + 0.16], 0.014);
const saddleBody = ellipse(0.115, 0.028, [SEAT_X - 0.01, SEAT_Y + 0.195]);
const saddleTip  = ellipse(0.028, 0.022, [SEAT_X + 0.096, SEAT_Y + 0.192]);
const saddle     = union(saddleBody, saddleTip);

// ─────────────────────────────────────────────────────────────
// PEDAL CRANK + PEDALS
// ─────────────────────────────────────────────────────────────
const crankR   = segment([BB_X, BB_Y], [BB_X + 0.13, BB_Y - 0.09], 0.014);
const crankL   = segment([BB_X, BB_Y], [BB_X - 0.13, BB_Y + 0.09], 0.013);
const pedalR   = rounded_rectangle([0.072, 0.018], 0.009, [BB_X + 0.145, BB_Y - 0.093]);
const pedalL   = rounded_rectangle([0.072, 0.018], 0.009, [BB_X - 0.145, BB_Y + 0.093]);
const chainRing = ring(0.075, 0.018, [BB_X, BB_Y]);
const pedals   = union(crankR, crankL, pedalR, pedalL, chainRing);

// ─────────────────────────────────────────────────────────────
// FRONT LIGHT (vintage acetylene lamp)
// ─────────────────────────────────────────────────────────────
const lampBody  = rounded_rectangle([0.052, 0.068], 0.014,  [HEAD_X + 0.06, HEAD_Y + 0.01]);
const lampLens  = circle(0.020, [HEAD_X + 0.082, HEAD_Y + 0.012]);
const lamp      = union(lampBody, lampLens);

// ─────────────────────────────────────────────────────────────
// MUDGUARDS (arcs over each wheel)
// ─────────────────────────────────────────────────────────────
const guardR = difference(
  ring(WHEEL_R + 0.034, 0.022, [RIGHT_CX, WHEEL_Y]),
  rectangle([2.0, 1.0], [RIGHT_CX, WHEEL_Y - 0.52])
);
const guardL = difference(
  ring(WHEEL_R + 0.034, 0.022, [LEFT_CX, WHEEL_Y]),
  rectangle([2.0, 1.0], [LEFT_CX, WHEEL_Y - 0.52])
);
const mudguards = union(guardR, guardL);

// ─────────────────────────────────────────────────────────────
// GROUND SHADOW
// ─────────────────────────────────────────────────────────────
const groundShadow = ellipse(0.60, 0.04, [0.0, WHEEL_Y - WHEEL_R - 0.018]);

// ─────────────────────────────────────────────────────────────
// LAYERS
// ─────────────────────────────────────────────────────────────
const layers = [
  // ground shadow
  { sdf: groundShadow,              color: [185, 170, 148] },

  // wheels: outline then fill
  { sdf: dilate(wheels, 0.022),     color: SHADOW },
  { sdf: wheels,                    color: DARK_BROWN },

  // mudguards
  { sdf: dilate(mudguards, 0.014),  color: SHADOW },
  { sdf: mudguards,                 color: RUST },

  // frame
  { sdf: dilate(frame, 0.022),      color: SHADOW },
  { sdf: frame,                     color: RUST },

  // head tube
  { sdf: dilate(headTube, 0.014),   color: SHADOW },
  { sdf: headTube,                  color: RUST },

  // pedals + chainring
  { sdf: dilate(pedals, 0.016),     color: SHADOW },
  { sdf: pedals,                    color: BRASS },

  // handlebar
  { sdf: dilate(handlebar, 0.014),  color: SHADOW },
  { sdf: handlebar,                 color: BRASS },

  // seat post + saddle
  { sdf: dilate(seatPost, 0.014),   color: SHADOW },
  { sdf: seatPost,                  color: DARK_BROWN },
  { sdf: dilate(saddle, 0.013),     color: SHADOW },
  { sdf: saddle,                    color: LEATHER },

  // lamp
  { sdf: dilate(lamp, 0.012),       color: SHADOW },
  { sdf: lamp,                      color: BRASS },
  { sdf: lampLens,                  color: [240, 230, 180] },
];

// ─────────────────────────────────────────────────────────────
// RENDER
// ─────────────────────────────────────────────────────────────
const canvas = document.getElementById('c');
const ctx    = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.25,
  background: { top: [232, 224, 208], bottom: [215, 205, 185] },
});
```

**Composition notes:**

The bicycle is built around the classic **diamond frame** — five named structural tubes (top, down, seat, chain-stay, seat-stay) plus a two-leg fork — all rendered as `segment` capsules so their varying angles come for free. Wheel spokes are 12 computed `segment` calls per wheel, with the loop ensuring even angular spacing; the outer `ring` primitive handles the tyre cross-section cleanly without needing a `difference`. I graded outline thickness by visual hierarchy: chunky `0.022` shadow on the main frame and wheels, finer `0.013–0.016` on the fork and seat-stay, and the thinnest `0.012` on the small lamp — this creates the depth-of-field illusion that flat-colour silhouettes otherwise lose.

The palette draws on Charley Harper's love of warm terracottas and neutral creams but leans into the **vintage vélo de ville** tradition: rust frame (referencing old French touring bikes), brass fittings, and a worn-leather saddle. The mudguards repeat the rust to tie the silhouette together. The teardrop acetylene lamp is a deliberate period detail — its brass body and cream lens add a focal highlight near the right edge. The warm taupe gradient background echoes the cobblestones of a Parisian side-street without needing any additional geometry.
